{
  "domain_analysis": {
    "business_context": "Order cancellation is a critical lifecycle event in logistics. An order moves through distinct fulfillment stages — each stage changes who bears cost, what physical actions have already occurred, and whether reversal is even possible. The phrase 'cancel their order' is deceptively simple; correctness depends entirely on the order's current state in the fulfillment pipeline.",
    "bounded_context": "Order Management / Order Lifecycle",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A customer's request for pickup and delivery of a package, tracked from creation through final delivery or terminal cancellation." },
      { "term": "Order Status", "definition": "The current position of an order in the fulfillment lifecycle (e.g., Placed, Confirmed, Assigned, Picked Up, In Transit, Out for Delivery, Delivered)." },
      { "term": "Cancellation", "definition": "A customer-initiated request to terminate an order before successful delivery. Not all cancellations are free; cost depends on fulfillment stage." },
      { "term": "Cancellation Window", "definition": "The set of order statuses during which cancellation is permitted. Once an order exits this window, cancellation is no longer possible through self-service." },
      { "term": "Cancellation Fee", "definition": "A charge applied when cancellation occurs after resources (courier time, fuel, vehicle capacity) have already been committed." },
      { "term": "Refund", "definition": "The return of payment to the customer upon successful cancellation, minus any applicable cancellation fee." },
      { "term": "Courier", "definition": "The assigned driver/rider responsible for physical pickup and delivery of the package." },
      { "term": "Fulfillment Stage", "definition": "A phase in the physical execution of the order — distinguishes between pre-dispatch (no physical cost incurred) and post-dispatch (courier en route or package in hand)." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "An order may only be cancelled by the customer who placed it (the order owner).",
      "invariant": true,
      "invariant_justification": "Allowing any user to cancel any order is a data integrity and authorization violation. Ownership is a hard security constraint.",
      "testable_assertion": "Given user A owns order 123 and user B attempts to cancel order 123, the system must reject the request with an authorization error."
    },
    {
      "id": "BR-2",
      "rule": "An order that has reached a terminal status (Delivered, Already Cancelled) cannot be cancelled.",
      "invariant": true,
      "invariant_justification": "A delivered package has physically changed hands. A cancelled order is already terminal. Allowing cancellation of terminal states corrupts the order lifecycle state machine.",
      "testable_assertion": "Given an order with status Delivered, when the customer requests cancellation, then the system must reject with 'Order cannot be cancelled — it has already been delivered.'"
    },
    {
      "id": "BR-3",
      "rule": "An order in status Placed or Confirmed (pre-dispatch) may be cancelled with no fee and a full refund.",
      "invariant": false,
      "invariant_justification": "The zero-fee window is a business policy. A VP could decide to always charge a small processing fee. The existence of a pre-dispatch tier is policy, not physics.",
      "testable_assertion": "Given an order in status Placed, when the customer cancels, then the cancellation fee is 0 and the refund equals the full order amount."
    },
    {
      "id": "BR-4",
      "rule": "An order in status Assigned or Picked Up (post-dispatch, pre-delivery) may be cancelled but incurs a cancellation fee.",
      "invariant": false,
      "invariant_justification": "The fee amount and whether post-dispatch cancellation is allowed at all are business policy decisions, not system invariants.",
      "testable_assertion": "Given an order in status Assigned, when the customer cancels, then the cancellation is accepted AND a cancellation fee is deducted from the refund amount."
    },
    {
      "id": "BR-5",
      "rule": "An order in status In Transit or Out for Delivery cannot be cancelled via self-service. The customer must contact support.",
      "invariant": false,
      "invariant_justification": "Whether late-stage cancellation requires human intervention is a policy choice, not a physical constraint. But the rationale is strong: the package is physically moving and reversal requires coordination.",
      "testable_assertion": "Given an order in status In Transit, when the customer attempts self-service cancellation, then the system must reject with a message directing them to customer support."
    },
    {
      "id": "BR-6",
      "rule": "When an order is cancelled, the assigned courier (if any) must be notified immediately.",
      "invariant": true,
      "invariant_justification": "A courier acting on a cancelled order wastes real resources and creates a broken physical state — courier has package but no valid order. This is a consistency invariant between digital and physical worlds.",
      "testable_assertion": "Given an order in status Assigned is cancelled, then within the same transaction boundary, a cancellation notification event is published for the assigned courier."
    },
    {
      "id": "BR-7",
      "rule": "Cancellation is idempotent: cancelling an already-cancelled order returns success with the original cancellation details, not an error.",
      "invariant": true,
      "invariant_justification": "Network retries, double-clicks, and UI race conditions make duplicate requests inevitable. Treating a repeat cancellation as an error creates confusion and support tickets. Idempotency is a system integrity requirement.",
      "testable_assertion": "Given an order already cancelled at time T1, when the customer sends a second cancellation request at T2, then the system returns HTTP 200 with the original cancellation timestamp T1 and original refund amount."
    },
    {
      "id": "BR-8",
      "rule": "Every cancellation must be recorded as an auditable event with timestamp, actor, reason, order status at time of cancellation, and fee applied.",
      "invariant": true,
      "invariant_justification": "Financial reversals (refunds) require an audit trail. Without it, dispute resolution is impossible and financial reconciliation breaks down.",
      "testable_assertion": "Given a successful cancellation, then an OrderCancelled event is persisted containing: orderId, customerId, cancelledAt, orderStatusAtCancellation, cancellationFee, refundAmount, and optional reason."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A customer has an order in status Placed",
      "when": "The customer requests cancellation of that order",
      "then": "The order status transitions to Cancelled, a full refund is issued with no fee, and a confirmation is shown to the customer"
    },
    {
      "id": "AC-2",
      "given": "A customer has an order in status Confirmed",
      "when": "The customer requests cancellation of that order",
      "then": "The order status transitions to Cancelled, a full refund is issued with no fee, and a confirmation is shown to the customer"
    },
    {
      "id": "AC-3",
      "given": "A customer has an order in status Assigned (courier assigned but package not yet picked up)",
      "when": "The customer requests cancellation of that order",
      "then": "The order status transitions to Cancelled, a refund minus the cancellation fee is issued, the assigned courier is notified of the cancellation, and the customer sees the fee breakdown"
    },
    {
      "id": "AC-4",
      "given": "A customer has an order in status Picked Up (courier has the package)",
      "when": "The customer requests cancellation of that order",
      "then": "The order status transitions to Cancelled, a refund minus the cancellation fee is issued, the courier is instructed to return the package, and the customer sees the fee breakdown"
    },
    {
      "id": "AC-5",
      "given": "A customer has an order in status In Transit",
      "when": "The customer attempts self-service cancellation",
      "then": "The cancellation is rejected, the order status remains unchanged, and the customer is shown a message with a direct link or phone number to contact support"
    },
    {
      "id": "AC-6",
      "given": "A customer has an order in status Out for Delivery",
      "when": "The customer attempts self-service cancellation",
      "then": "The cancellation is rejected, the order status remains unchanged, and the customer is directed to contact support"
    },
    {
      "id": "AC-7",
      "given": "A customer has an order in status Delivered",
      "when": "The customer attempts cancellation",
      "then": "The cancellation is rejected with a clear message: 'This order has already been delivered and cannot be cancelled. Please contact support for returns.'"
    },
    {
      "id": "AC-8",
      "given": "A customer has an order that was already cancelled",
      "when": "The customer sends another cancellation request (duplicate/retry)",
      "then": "The system returns success with the original cancellation details (timestamp, refund amount) without creating a duplicate event or issuing a second refund"
    },
    {
      "id": "AC-9",
      "given": "User B does NOT own order 123",
      "when": "User B attempts to cancel order 123",
      "then": "The system rejects the request with an authorization error and no state change occurs on the order"
    },
    {
      "id": "AC-10",
      "given": "An order in status Assigned is successfully cancelled",
      "when": "The cancellation is persisted",
      "then": "A courier notification is dispatched in the same transactional boundary, and an OrderCancelled audit event is recorded with all required fields"
    },
    {
      "id": "AC-11",
      "given": "A customer initiates cancellation but the order status changes (e.g., courier picks up) during the request",
      "when": "The cancellation is processed",
      "then": "The system evaluates cancellability against the order's status at the moment of state transition (optimistic locking), not at the moment the UI was loaded. If the order moved to a non-cancellable state, the request is rejected with the current status."
    }
  ],

  "edge_cases": [
    {
      "scenario": "Race condition: customer cancels while courier simultaneously marks the order as Picked Up",
      "expected_behavior": "Exactly one operation wins via optimistic locking or equivalent concurrency control. If pickup wins, cancellation is rejected with the updated status. If cancellation wins, the courier's pickup attempt is rejected and courier is notified the order is cancelled. The system must never reach a state where the order is both Cancelled and Picked Up."
    },
    {
      "scenario": "Customer cancels immediately after payment but before payment confirmation is fully processed",
      "expected_behavior": "Cancellation must wait for payment state to settle. If payment is still pending, the cancellation queues behind payment completion. The refund is only issued against a confirmed charge — never a void against a pending-but-unconfirmed payment, unless the payment gateway supports void explicitly."
    },
    {
      "scenario": "Network timeout: cancellation request succeeds server-side but the response is lost",
      "expected_behavior": "The customer retries. Because cancellation is idempotent (BR-7), the second request returns the original cancellation result. No double refund. No error."
    },
    {
      "scenario": "Customer has multiple active orders and cancels the wrong one",
      "expected_behavior": "The cancellation UI must show unambiguous order identification (order number, pickup/delivery addresses, date) on the confirmation screen. A confirmation step ('Are you sure you want to cancel order #X?') is required before execution."
    },
    {
      "scenario": "Cancellation of an order that used a promotional discount or coupon",
      "expected_behavior": "Refund amount is the amount actually charged, not the pre-discount price. The promotional credit or coupon should be re-credited to the customer's account per the promotion's terms (some promos are one-time-use and should be restored; others are not)."
    },
    {
      "scenario": "Cancellation of a partially fulfilled multi-package order",
      "expected_behavior": "If the system supports multi-package orders, cancellation applies to un-picked-up items only. Already-picked-up packages follow the post-dispatch cancellation flow (fee + courier return). The refund is prorated per package."
    },
    {
      "scenario": "Customer cancels, receives refund, then disputes the charge with their bank anyway",
      "expected_behavior": "The audit trail (BR-8) provides evidence that the refund was already issued. This is not a system behavior but the audit record is the critical artifact for dispute resolution."
    },
    {
      "scenario": "System outage: cancellation service is down but the customer wants to cancel before the window closes",
      "expected_behavior": "The system should return a clear error indicating temporary unavailability and advise the customer to retry shortly or contact support. The order status must not change. No partial state."
    }
  ],

  "business_impact": {
    "financial": "Every cancellation is a direct revenue reversal. Free cancellations pre-dispatch have low cost; post-dispatch cancellations with fees partially recover sunk courier costs. Incorrect refund logic (double refunds, missing fees) directly impacts margin. Overly restrictive cancellation policies increase chargeback rates, which carry penalty fees from payment processors.",
    "operational": "Post-dispatch cancellations create courier deadhead (empty return trips), reducing fleet efficiency. Courier notification latency directly correlates with wasted miles. High cancellation rates may indicate upstream UX or pricing problems worth investigating.",
    "user": "Cancellation is a trust-building feature. Customers who know they can cancel are more likely to place orders. Friction-free pre-dispatch cancellation improves NPS. Opaque or restrictive cancellation flows drive negative reviews and support volume.",
    "risk": "Primary risks: (1) Race conditions causing split-brain between order status and physical package location. (2) Double-refund bugs causing financial loss. (3) Missing courier notifications causing real-world confusion — courier arrives at pickup for a cancelled order. (4) Regulatory risk in some jurisdictions that mandate cancellation rights within specific windows.",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Direct users of the feature. Poor UX or restrictive policies erode trust and increase churn." },
      { "group": "Couriers", "impact": "Must receive timely cancellation notifications to avoid wasted trips. Late notifications directly reduce courier earnings and satisfaction." },
      { "group": "Customer Support", "impact": "Handles overflow from non-self-service cancellations (In Transit, Out for Delivery). Volume depends on how many orders reach late stages before customers want to cancel." },
      { "group": "Finance/Accounting", "impact": "Refunds affect revenue recognition, reconciliation, and reporting. Audit trail quality directly impacts month-end close." },
      { "group": "Product/Growth", "impact": "Cancellation rate is a key health metric. Cancellation reasons data informs product improvements." }
    ]
  },

  "confidence": {
    "level": 42,
    "reasoning": "The spec is a single sentence with no definition of order statuses, cancellation fees, refund policies, or scope boundaries. Every business rule above is inferred from logistics domain expertise, not from an actual spec. The status names, fee structure, and cancellation window boundaries are all assumptions that require PM confirmation. This confidence level reflects the extreme vagueness of the input spec, not the quality of the analysis.",
    "high_confidence_areas": [
      "Terminal statuses (Delivered, already Cancelled) must block cancellation — this is universally true in logistics",
      "Cancellation must be idempotent — this is a system integrity requirement regardless of domain",
      "Audit trail is required for any financial reversal",
      "Courier notification on post-assignment cancellation is a physical-world consistency requirement"
    ],
    "low_confidence_areas": [
      "Exact order status names and lifecycle stages — must be learned from the actual codebase",
      "Whether cancellation fees exist at all, and their amounts",
      "The cutoff point between self-service and support-only cancellation",
      "Whether multi-package orders exist in this system",
      "Promotional/coupon reinstatement policy",
      "Whether the system is prepaid or pay-on-delivery (changes refund logic entirely)"
    ],
    "assumptions": [
      "The system uses prepaid orders (customer pays at order time, refund is needed on cancellation)",
      "Orders follow a linear lifecycle: Placed → Confirmed → Assigned → Picked Up → In Transit → Out for Delivery → Delivered",
      "There is exactly one courier assigned per order",
      "Cancellation fees are a flat amount, not percentage-based",
      "The 'user' in the PM statement means the customer who placed the order, not an admin or support agent"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define which order statuses exist, nor at which stage cancellation should be blocked. The entire cancellation window policy is undefined.",
      "affected_stakeholders": ["Customers", "Couriers", "Customer Support", "Finance"],
      "options": [
        "A: Allow cancellation at any pre-delivery stage (most permissive, highest courier cost)",
        "B: Allow self-service only pre-dispatch, require support post-dispatch (balanced)",
        "C: Allow cancellation only before courier assignment (most restrictive, lowest cost)"
      ],
      "recommendation": "Option B — it balances customer experience with operational cost and is the industry standard for courier platforms."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not mention cancellation fees. Should there be a fee for late cancellations, and if so, how much?",
      "affected_stakeholders": ["Customers", "Finance", "Product/Growth"],
      "options": [
        "A: No fees ever — full refund regardless of stage",
        "B: Tiered fees based on fulfillment stage",
        "C: Flat fee for any post-assignment cancellation"
      ],
      "recommendation": "Option B — tiered fees align cost recovery with actual resources consumed and are fairest to customers."
    },
    {
      "type": "missing_context",
      "description": "Unknown whether the payment model is prepaid or pay-on-delivery. This fundamentally changes whether 'refund' means returning money or simply not charging.",
      "affected_stakeholders": ["Customers", "Finance"],
      "options": [
        "Clarify payment model with PM before implementation"
      ],
      "recommendation": "Block implementation of the refund flow until payment model is confirmed."
    },
    {
      "type": "ambiguity",
      "description": "The spec says 'users' — does this include admin/support cancellation, or only customer self-service? Admin cancellation has different rules (no fee, broader status window).",
      "affected_stakeholders": ["Customer Support", "Customers"],
      "options": [
        "A: Scope to customer self-service only",
        "B: Include both customer and admin cancellation flows"
      ],
      "recommendation": "Option A for initial scope — admin cancellation is a separate feature with different authorization and business rules."
    }
  ],

  "rejection_reasons": []
}

